```

### Socket.IO Channel Architecture

```typescript
// apps/api/src/realtime/channels.ts
export enum SocketChannel {
  SERVER_STATUS = 'server-status',
  MARKETPLACE_UPDATES = 'marketplace-updates',
  GUILD_EVENTS = 'guild-events',
  TERRITORY_WAR = 'territory-war',
  PERSONAL_NOTIFICATIONS = 'personal-notifications',
}

// Event payloads
interface ServerStatusEvent {
  serverId: string;
  name: string;
  status: 'online' | 'offline' | 'busy' | 'maintenance';
  playerCount: number;
  maxPlayers: number;
  ping: number;
  maintenanceETA?: string;
}

interface TerritoryUpdateEvent {
  territoryId: string;
  newOwnerId: string | null;
  guildName: string | null;
  guildColor: string;
  captureDate: string;
  isUnderSiege: boolean;
}

interface MarketplaceEvent {
  type: 'listing_created' | 'listing_sold' | 'auction_bid' | 'price_change';
  listingId: string;
  itemId: string;
  price: number;
  timestamp: string;
}
```

