   *
   * For any listing creation input, the validation SHALL accept the input if and only if:
   * name length is in [1, 100], description length is in [0, 500], quantity is an integer
   * in [1, 9999], price is in [0.01, 999999999.99], and duration is an integer in [1, 168].
   * For auction inputs, additionally: startingBid >= 0.01 and minIncrement >= 0.01.
   */

  let service: MarketplaceService;
  let mockDb: ReturnType<typeof createMockDb>;

