describe('Feature: perfect-world-neo-brutalism, Property 16: Transaction Fee Computation', () => {
  /**
   * **Validates: Requirements 8.6**
   *
   * For any completed marketplace sale with price P and configured fee percentage F
   * (where 0.1 <= F <= 25.0), the fee deducted SHALL equal P * (F/100) rounded to
   * 2 decimal places, and the seller's proceeds SHALL equal P - fee.
   */

  let service: MarketplaceService;
  let mockDb: ReturnType<typeof createMockDb>;

  beforeEach(() => {
    mockDb = createMockDb();
    service = new MarketplaceService(mockDb as any);
  });

  it('fee is always between 0.1% and 25% of the sale amount', () => {
    fc.assert(
      fc.property(validFeePercentArb, validSaleAmountArb, (feePercent, amount) => {
        service.setTransactionFeePercent(feePercent);
        const fee = service.computeTransactionFee(amount);

        // Fee must be non-negative
        expect(fee).toBeGreaterThanOrEqual(0);

        // Fee must not exceed 25% of the amount
        const maxFee = Math.round(amount * (MARKETPLACE.TRANSACTION_FEE_MAX_PERCENT / 100) * 100) / 100;
        expect(fee).toBeLessThanOrEqual(maxFee + 0.01);

        // Fee must be at least 0.1% of the amount (for amounts large enough)
        if (amount >= 1) {
          const minFee = Math.round(amount * (MARKETPLACE.TRANSACTION_FEE_MIN_PERCENT / 100) * 100) / 100;
          expect(fee).toBeGreaterThanOrEqual(minFee - 0.01);
        }
      }),
      { numRuns: 500 },
    );
  });

  it('fee equals P * (F/100) correctly rounded to 2 decimal places', () => {
    fc.assert(
      fc.property(validFeePercentArb, validSaleAmountArb, (feePercent, amount) => {
        service.setTransactionFeePercent(feePercent);
        const fee = service.computeTransactionFee(amount);

        const expectedFee = Math.round(amount * (feePercent / 100) * 100) / 100;
        expect(fee).toBeCloseTo(expectedFee, 2);
      }),
      { numRuns: 500 },
    );
  });

  it('seller proceeds equal sale amount minus fee', () => {
    fc.assert(
      fc.property(validFeePercentArb, validSaleAmountArb, (feePercent, amount) => {
        service.setTransactionFeePercent(feePercent);
        const fee = service.computeTransactionFee(amount);
        const sellerProceeds = amount - fee;

        expect(sellerProceeds).toBeGreaterThanOrEqual(0);
        expect(sellerProceeds + fee).toBeCloseTo(amount, 2);
      }),
      { numRuns: 500 },
    );
  });

  it('fee is always rounded to at most 2 decimal places', () => {
    fc.assert(
      fc.property(validFeePercentArb, validSaleAmountArb, (feePercent, amount) => {
        service.setTransactionFeePercent(feePercent);
        const fee = service.computeTransactionFee(amount);

        const rounded = Math.round(fee * 100) / 100;
        expect(fee).toBe(rounded);
      }),
      { numRuns: 500 },
    );
  });
});

